Rules.InvariantScript:
Notify(
    "Registration successful!",
    NotificationType.Success,
    3000
);
If(
    Form2_1.LastSubmit.MyRole.Value = "Volunteer",
    Navigate('volunteer''s page'),
    Navigate('coordinator''s page')
)

Set(
    currentUser,
    LookUp(
        'Volunteer&Coordinator login',
        Name = LoginNameInput.Value &&
        Email = LoginEmailInput.Value
    )
);

If(
    IsBlank(currentUser),
    Notify("User not found", NotificationType.Error),

    Set(currentRole, currentUser.MyRole.Value);

    Set(varLat, Location.Latitude);
    Set(varLng, Location.Longitude);

    Patch(
        'Volunteer&Coordinator login',
        currentUser,
        {
            Latitude: varLat,
            Longitude: varLng
        }
    );

    If(
        currentUser.MyRole.Value = "Volunteer",
        Set(currentPage, "Volunteer");
        Navigate('volunteer''s page'),

        Set(currentPage, "Coordinator");
        Navigate('coordinator''s page')
    )
)

